// src/views/liste.manager.js
import React, { useState, useEffect } from "react";
import ManagerCard from "components/Common/managerCard";
import Footer from "components/Footers/Footer.js";
import Navbar from "components/Navbars/AuthNavbar.js";

export default function ManagersList() {
  const [managers, setManagers] = useState([]);
  const [loading, setLoading] = useState(true);
  const [searchTerm, setSearchTerm] = useState("");
  const [filterStatus, setFilterStatus] = useState("all");
  const [selectedManager, setSelectedManager] = useState(null);

  // بيانات المديرين التجريبية
  useEffect(() => {
    // محاكاة جلب البيانات من API
    setTimeout(() => {
      const mockManagers = [
        {
          id: 1,
          name: "Ahmed Benali",
          role: "Directeur Général",
          profileImage: "https://randomuser.me/api/portraits/men/32.jpg",
          location: "Alger, Algérie",
          rating: 4.9,
          employees: 45,
          restaurantCount: 3,
          experience: "12 ans d'expérience",
          skills: ["Management", "Gestion d'équipe", "Marketing", "Finance"],
          status: "active",
          email: "ahmed.benali@example.com",
          phone: "+213 5 55 55 55 55"
        },
        {
          id: 2,
          name: "Karim El Fassi",
          role: "Directeur des Opérations",
          profileImage: "https://randomuser.me/api/portraits/men/45.jpg",
          location: "Casablanca, Maroc",
          rating: 4.8,
          employees: 32,
          restaurantCount: 2,
          experience: "8 ans d'expérience",
          skills: ["Operations", "Logistique", "Gestion", "RH"],
          status: "active",
          email: "karim.elfassi@example.com",
          phone: "+212 6 12 34 56 78"
        },
        {
          id: 3,
          name: "Sophie Martin",
          role: "Directrice Commerciale",
          profileImage: "https://randomuser.me/api/portraits/women/28.jpg",
          location: "Paris, France",
          rating: 4.7,
          employees: 28,
          restaurantCount: 2,
          experience: "10 ans d'expérience",
          skills: ["Commercial", "Marketing", "Relations clients", "Négociation"],
          status: "active",
          email: "sophie.martin@example.com",
          phone: "+33 6 12 34 56 78"
        },
        {
          id: 4,
          name: "Youssef Mansouri",
          role: "Directeur Financier",
          profileImage: "https://randomuser.me/api/portraits/men/67.jpg",
          location: "Tunis, Tunisie",
          rating: 4.6,
          employees: 22,
          restaurantCount: 1,
          experience: "7 ans d'expérience",
          skills: ["Finance", "Comptabilité", "Audit", "Gestion"],
          status: "inactive",
          email: "youssef.mansouri@example.com",
          phone: "+216 5 55 55 55 55"
        },
        {
          id: 5,
          name: "Laila Hakimi",
          role: "Directrice Marketing",
          profileImage: "https://randomuser.me/api/portraits/women/42.jpg",
          location: "Dubai, UAE",
          rating: 4.9,
          employees: 15,
          restaurantCount: 1,
          experience: "6 ans d'expérience",
          skills: ["Marketing digital", "Réseaux sociaux", "Branding", "Communication"],
          status: "active",
          email: "laila.hakimi@example.com",
          phone: "+971 5 55 55 55 55"
        },
        {
          id: 6,
          name: "Omar Benjelloun",
          role: "Directeur Régional",
          profileImage: "https://randomuser.me/api/portraits/men/89.jpg",
          location: "Rabat, Maroc",
          rating: 4.8,
          employees: 55,
          restaurantCount: 4,
          experience: "15 ans d'expérience",
          skills: ["Management", "Développement", "Stratégie", "Leadership"],
          status: "active",
          email: "omar.benjelloun@example.com",
          phone: "+212 6 98 76 54 32"
        }
      ];
      setManagers(mockManagers);
      setLoading(false);
    }, 1000);
  }, []);

  // تصفية المديرين حسب البحث والحالة
  const filteredManagers = managers.filter(manager => {
    const matchesSearch = manager.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
                          manager.role.toLowerCase().includes(searchTerm.toLowerCase()) ||
                          manager.location.toLowerCase().includes(searchTerm.toLowerCase());
    const matchesStatus = filterStatus === "all" || manager.status === filterStatus;
    return matchesSearch && matchesStatus;
  });

  const handleManagerClick = (manager) => {
    setSelectedManager(manager);
    alert(`👤 ${manager.name}\n📧 ${manager.email}\n📞 ${manager.phone}\n📍 ${manager.location}\n⭐ ${manager.rating}/5`);
  };

  return (
    <>
      <Navbar />
      
      <div className="managers-list-container">
        {/* خلفية متحركة */}
        <div className="bg-gradient"></div>
        <div className="noise-overlay"></div>
        <div className="top-glow"></div>
        <div className="bottom-glow"></div>
        
        <div className="container">
          {/* Header */}
          <div className="header-section">
            <h1 className="page-title">👨‍💼 Gestion des Managers</h1>
            <p className="page-subtitle">Liste de tous les managers et directeurs</p>
            
            {/* Search and Filter */}
            <div className="search-filter-section">
              <div className="search-box">
                <span className="search-icon">🔍</span>
                <input
                  type="text"
                  placeholder="Rechercher un manager..."
                  value={searchTerm}
                  onChange={(e) => setSearchTerm(e.target.value)}
                />
              </div>
              
              <div className="filter-buttons">
                <button 
                  className={`filter-btn ${filterStatus === "all" ? "active" : ""}`}
                  onClick={() => setFilterStatus("all")}
                >
                  Tous ({managers.length})
                </button>
                <button 
                  className={`filter-btn ${filterStatus === "active" ? "active" : ""}`}
                  onClick={() => setFilterStatus("active")}
                >
                  ✅ Actifs ({managers.filter(m => m.status === "active").length})
                </button>
                <button 
                  className={`filter-btn ${filterStatus === "inactive" ? "active" : ""}`}
                  onClick={() => setFilterStatus("inactive")}
                >
                  ⏸️ Inactifs ({managers.filter(m => m.status === "inactive").length})
                </button>
              </div>
            </div>
          </div>
          
          {/* Loading Spinner */}
          {loading ? (
            <div className="loading-container">
              <div className="spinner"></div>
              <p>Chargement des managers...</p>
            </div>
          ) : (
            <>
              {/* Statistics Cards */}
              <div className="stats-cards">
                <div className="stat-card">
                  <div className="stat-icon">👨‍💼</div>
                  <div className="stat-info">
                    <h3>{managers.length}</h3>
                    <p>Total Managers</p>
                  </div>
                </div>
                <div className="stat-card">
                  <div className="stat-icon">⭐</div>
                  <div className="stat-info">
                    <h3>{(managers.reduce((acc, m) => acc + m.rating, 0) / managers.length || 0).toFixed(1)}</h3>
                    <p>Note moyenne</p>
                  </div>
                </div>
                <div className="stat-card">
                  <div className="stat-icon">🏪</div>
                  <div className="stat-info">
                    <h3>{managers.reduce((acc, m) => acc + m.restaurantCount, 0)}</h3>
                    <p>Restaurants gérés</p>
                  </div>
                </div>
                <div className="stat-card">
                  <div className="stat-icon">👥</div>
                  <div className="stat-info">
                    <h3>{managers.reduce((acc, m) => acc + m.employees, 0)}</h3>
                    <p>Employés supervisés</p>
                  </div>
                </div>
              </div>
              
              {/* Managers Grid */}
              {filteredManagers.length > 0 ? (
                <div className="managers-grid">
                  {filteredManagers.map((manager) => (
                    <ManagerCard
                      key={manager.id}
                      manager={manager}
                      onClick={() => handleManagerClick(manager)}
                    />
                  ))}
                </div>
              ) : (
                <div className="no-results">
                  <div className="no-results-icon">🔍</div>
                  <h3>Aucun manager trouvé</h3>
                  <p>Essayez de modifier vos critères de recherche</p>
                </div>
              )}
            </>
          )}
        </div>
      </div>
      
      <Footer />
      
      <style jsx>{`
        * {
          margin: 0;
          padding: 0;
          box-sizing: border-box;
        }
        
        .managers-list-container {
          min-height: 100vh;
          width: 100%;
          position: relative;
          overflow-x: hidden;
          font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
          background: #0a0a0a;
        }
        
        .bg-gradient {
          position: fixed;
          inset: 0;
          background: radial-gradient(ellipse at 50% 30%, 
            #19022a 0%,
            #1c084b 30%,
            #1a0b2e 60%,
            #0a0a0a 85%,
            #050505 100%
          );
          z-index: 0;
        }
        
        .noise-overlay {
          position: fixed;
          inset: 0;
          opacity: 0.03;
          background-image: url("data:image/svg+xml,%3Csvg viewBox='0 0 200 200' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='n'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='0.65' numOctaves='3'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23n)'/%3E%3C/svg%3E");
          background-size: 200px 200px;
          pointer-events: none;
          z-index: 1;
        }
        
        .top-glow {
          position: fixed;
          top: 0;
          left: 50%;
          transform: translateX(-50%);
          width: 120vh;
          height: 60vh;
          border-radius: 0 0 50% 50%;
          background: radial-gradient(ellipse at center, rgba(139, 92, 246, 0.3), rgba(107, 70, 193, 0.1), transparent);
          filter: blur(80px);
          z-index: 0;
          animation: pulseGlow 8s ease-in-out infinite;
        }
        
        .bottom-glow {
          position: fixed;
          bottom: 0;
          left: 50%;
          transform: translateX(-50%);
          width: 90vh;
          height: 90vh;
          border-radius: 50% 50% 0 0;
          background: radial-gradient(ellipse at center, rgba(168, 85, 247, 0.25), rgba(126, 34, 206, 0.1), transparent);
          filter: blur(60px);
          z-index: 0;
          animation: pulseGlowBottom 6s ease-in-out infinite;
        }
        
        @keyframes pulseGlow {
          0%, 100% { opacity: 0.4; transform: translateX(-50%) scale(0.98); }
          50% { opacity: 0.7; transform: translateX(-50%) scale(1.02); }
        }
        
        @keyframes pulseGlowBottom {
          0%, 100% { opacity: 0.3; transform: translateX(-50%) scale(1); }
          50% { opacity: 0.6; transform: translateX(-50%) scale(1.08); }
        }
        
        .container {
          position: relative;
          z-index: 10;
          max-width: 1400px;
          margin: 0 auto;
          padding: 100px 20px 60px;
        }
        
        .header-section {
          text-align: center;
          margin-bottom: 40px;
        }
        
        .page-title {
          font-size: 2.5rem;
          font-weight: bold;
          background: linear-gradient(135deg, white, #a855f7);
          -webkit-background-clip: text;
          background-clip: text;
          color: transparent;
          margin-bottom: 10px;
        }
        
        .page-subtitle {
          color: rgba(255,255,255,0.6);
          font-size: 1rem;
          margin-bottom: 30px;
        }
        
        .search-filter-section {
          display: flex;
          justify-content: center;
          align-items: center;
          gap: 20px;
          flex-wrap: wrap;
        }
        
        .search-box {
          display: flex;
          align-items: center;
          background: rgba(255,255,255,0.1);
          border: 1px solid rgba(255,255,255,0.2);
          border-radius: 30px;
          padding: 10px 20px;
          width: 300px;
        }
        
        .search-icon {
          font-size: 1rem;
          margin-right: 10px;
          color: rgba(255,255,255,0.5);
        }
        
        .search-box input {
          background: transparent;
          border: none;
          color: white;
          font-size: 0.9rem;
          outline: none;
          width: 100%;
        }
        
        .search-box input::placeholder {
          color: rgba(255,255,255,0.4);
        }
        
        .filter-buttons {
          display: flex;
          gap: 10px;
        }
        
        .filter-btn {
          background: rgba(255,255,255,0.1);
          border: 1px solid rgba(255,255,255,0.2);
          border-radius: 30px;
          padding: 8px 20px;
          color: rgba(255,255,255,0.7);
          cursor: pointer;
          transition: all 0.3s;
          font-size: 0.85rem;
        }
        
        .filter-btn:hover {
          background: rgba(255,255,255,0.2);
        }
        
        .filter-btn.active {
          background: linear-gradient(135deg, #22c55e, #15803d);
          border-color: #22c55e;
          color: white;
        }
        
        .stats-cards {
          display: grid;
          grid-template-columns: repeat(auto-fit, minmax(200px, 1fr));
          gap: 20px;
          margin-bottom: 40px;
        }
        
        .stat-card {
          background: rgba(255,255,255,0.08);
          backdrop-filter: blur(10px);
          border-radius: 20px;
          padding: 20px;
          display: flex;
          align-items: center;
          gap: 15px;
          border: 1px solid rgba(34,197,94,0.2);
          transition: all 0.3s;
        }
        
        .stat-card:hover {
          transform: translateY(-3px);
          border-color: #22c55e;
        }
        
        .stat-icon {
          font-size: 2rem;
        }
        
        .stat-info h3 {
          color: white;
          font-size: 1.8rem;
          margin: 0;
        }
        
        .stat-info p {
          color: rgba(255,255,255,0.6);
          font-size: 0.8rem;
          margin: 0;
        }
        
        .managers-grid {
          display: grid;
          grid-template-columns: repeat(auto-fill, minmax(320px, 1fr));
          gap: 25px;
          animation: fadeIn 0.5s ease-out;
        }
        
        @keyframes fadeIn {
          from { opacity: 0; transform: translateY(20px); }
          to { opacity: 1; transform: translateY(0); }
        }
        
        .loading-container {
          display: flex;
          flex-direction: column;
          align-items: center;
          justify-content: center;
          min-height: 400px;
        }
        
        .spinner {
          width: 50px;
          height: 50px;
          border: 3px solid rgba(255,255,255,0.2);
          border-top-color: #22c55e;
          border-radius: 50%;
          animation: spin 1s linear infinite;
        }
        
        @keyframes spin {
          to { transform: rotate(360deg); }
        }
        
        .loading-container p {
          color: rgba(255,255,255,0.6);
          margin-top: 15px;
        }
        
        .no-results {
          text-align: center;
          padding: 60px;
          background: rgba(255,255,255,0.05);
          border-radius: 30px;
        }
        
        .no-results-icon {
          font-size: 4rem;
          margin-bottom: 20px;
        }
        
        .no-results h3 {
          color: white;
          margin-bottom: 10px;
        }
        
        .no-results p {
          color: rgba(255,255,255,0.5);
        }
        
        @media (max-width: 768px) {
          .container {
            padding: 80px 15px 40px;
          }
          
          .page-title {
            font-size: 1.8rem;
          }
          
          .search-filter-section {
            flex-direction: column;
          }
          
          .search-box {
            width: 100%;
            max-width: 300px;
          }
          
          .managers-grid {
            grid-template-columns: 1fr;
          }
          
          .stats-cards {
            grid-template-columns: repeat(2, 1fr);
          }
        }
      `}</style>
    </>
  );
}
